import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api/axios';
import { Send, Building, AlertCircle, ArrowRight, CheckCircle, Loader } from 'lucide-react';

const ApplyRoom = () => {
    const [rooms, setRooms] = useState([]);
    const [application, setApplication] = useState(null);
    const [selectedRoom, setSelectedRoom] = useState('');
    const [requestMessage, setRequestMessage] = useState('');
    const [loading, setLoading] = useState(true);
    const [submitLoading, setSubmitLoading] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    const navigate = useNavigate();

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            // Check if already applied
            try {
                const { data: appData } = await api.get('/student/status');
                setApplication(appData);
                if (appData) {
                    setError('You have already applied for a room.');
                }
            } catch (err) {
                if (err.response?.status !== 404) {
                    throw err;
                }
            }

            // Fetch available rooms
            const { data: roomData } = await api.get('/student/rooms');
            setRooms(roomData);
        } catch (err) {
            setError('Failed to fetch data');
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!selectedRoom) {
            return setError('Please select a block to apply');
        }

        setSubmitLoading(true);
        setError('');
        try {
            await api.post('/student/apply', {
                roomId: selectedRoom,
                message: requestMessage // Not in backend schema but added to request per requirement
            });
            setSuccess('Application submitted successfully!');
            setTimeout(() => navigate('/student/status'), 2000);
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to submit application');
        } finally {
            setSubmitLoading(false);
        }
    };

    if (loading) {
        return (
            <div className="flex justify-center items-center h-[calc(100vh-64px)] bg-gray-50">
                <Loader className="animate-spin text-blue-600" size={48} />
            </div>
        );
    }

    return (
        <div className="min-h-[calc(100vh-64px)] bg-gray-50 p-6 md:p-12">
            <div className="max-w-2xl mx-auto space-y-8">

                <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100 mb-8 text-center">
                    <div className="w-16 h-16 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
                        <Send size={32} />
                    </div>
                    <h1 className="text-3xl font-bold text-gray-900">Room Application</h1>
                    <p className="text-gray-500 mt-2">Submit your request for hostel accommodation.</p>
                </div>

                {error && (
                    <div className="bg-red-50 text-red-600 p-4 rounded-xl flex items-center gap-3 font-medium border border-red-100">
                        <AlertCircle size={24} />
                        {error}
                    </div>
                )}

                {success && (
                    <div className="bg-green-50 text-green-600 p-4 rounded-xl flex items-center gap-3 font-medium border border-green-100 mb-6">
                        <CheckCircle size={24} />
                        {success}
                    </div>
                )}

                {!application && !success && (
                    <div className="bg-white rounded-3xl p-8 shadow-sm border border-gray-100">
                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div>
                                <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide mb-2">Select Preferred Block</label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <Building size={18} className="text-gray-400" />
                                    </div>
                                    <select
                                        required
                                        value={selectedRoom}
                                        onChange={(e) => setSelectedRoom(e.target.value)}
                                        className="block w-full pl-10 pr-10 py-3.5 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-gray-50 focus:bg-white transition-all outline-none appearance-none font-medium text-gray-800 cursor-pointer"
                                    >
                                        <option value="" disabled>Choose a block...</option>
                                        {rooms.map(room => (
                                            <option key={room._id} value={room._id}>
                                                Block {room.block} ({room.totalRooms - room.occupiedRooms} availability left)
                                            </option>
                                        ))}
                                    </select>
                                </div>
                                {rooms.length === 0 && (
                                    <p className="text-xs text-red-500 mt-2">No rooms currently available to apply.</p>
                                )}
                            </div>

                            <div>
                                <label className="block text-sm font-bold text-gray-700 uppercase tracking-wide mb-2">
                                    Special Request <span className="text-gray-400 text-xs font-normal lowercase">(Optional)</span>
                                </label>
                                <textarea
                                    className="block w-full p-4 border border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-blue-500 bg-gray-50 focus:bg-white transition-all outline-none text-gray-800 resize-none h-32"
                                    placeholder="Any specific requirements or notes..."
                                    value={requestMessage}
                                    onChange={(e) => setRequestMessage(e.target.value)}
                                ></textarea>
                            </div>

                            <button
                                type="submit"
                                disabled={submitLoading || rooms.length === 0}
                                className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white font-bold py-4 px-6 rounded-xl transition-all shadow-lg hover:shadow-blue-500/30 disabled:opacity-50 mt-8"
                            >
                                {submitLoading ? (
                                    <Loader className="animate-spin" size={24} />
                                ) : (
                                    <>Submit Application <ArrowRight size={20} /></>
                                )}
                            </button>
                        </form>
                    </div>
                )}

                {application && !success && (
                    <div className="bg-white rounded-3xl p-8 shadow-sm border border-gray-100 text-center">
                        <div className="w-16 h-16 bg-yellow-100 text-yellow-600 rounded-full flex items-center justify-center mx-auto mb-4">
                            <AlertCircle size={32} />
                        </div>
                        <h3 className="text-xl font-bold text-gray-900 mb-2">Already Applied</h3>
                        <p className="text-gray-500 mb-6">You have an active application. You cannot submit multiple applications simultaneously.</p>

                        <button
                            onClick={() => navigate('/student/status')}
                            className="bg-gray-100 text-gray-700 hover:bg-gray-200 font-bold py-3 px-6 rounded-xl transition-all"
                        >
                            View Status Instead
                        </button>
                    </div>
                )}

            </div>
        </div>
    );
};

export default ApplyRoom;

import { useState, useContext } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import api from '../api/axios';
import AuthContext from '../context/AuthContext';
import { User, Lock, Mail, BookOpen, Calendar, ArrowRight, Loader } from 'lucide-react';

const Register = () => {
    const [formData, setFormData] = useState({
        name: '',
        email: '',
        password: '',
        confirmPassword: '',
        department: '',
        year: ''
    });

    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);
    const { login } = useContext(AuthContext);
    const navigate = useNavigate();

    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');

        if (formData.password !== formData.confirmPassword) {
            return setError('Passwords do not match');
        }

        if (formData.password.length < 6) {
            return setError('Password must be at least 6 characters');
        }

        setLoading(true);
        try {
            const payload = { ...formData };
            delete payload.confirmPassword;

            const { data } = await api.post('/auth/register', payload);
            // Requirement: Redirect to login after successful registration
            navigate('/login');
        } catch (err) {
            setError(err.response?.data?.message || 'Registration failed');
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-[calc(100vh-64px)] bg-gray-50 flex items-center justify-center p-4 py-12">
            <div className="max-w-md w-full bg-white rounded-3xl shadow-xl overflow-hidden border border-gray-100">
                <div className="bg-indigo-600 p-6 text-white text-center">
                    <h2 className="text-3xl font-bold mb-1">Create Account</h2>
                    <p className="text-indigo-100 text-sm font-medium">Join HostelHub as a Student</p>
                </div>

                <div className="p-8">
                    {error && (
                        <div className="bg-red-50 text-red-600 p-3 rounded-lg mb-6 text-sm font-medium border border-red-100 text-center">
                            {error}
                        </div>
                    )}

                    <form onSubmit={handleSubmit} className="space-y-4">
                        <div>
                            <label className="block text-xs font-semibold text-gray-600 uppercase tracking-wide mb-1">Full Name</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <User size={16} className="text-gray-400" />
                                </div>
                                <input
                                    type="text"
                                    name="name"
                                    required
                                    className="block w-full pl-10 pr-3 py-2.5 border border-gray-200 rounded-xl focus:ring-indigo-500 focus:border-indigo-500 bg-gray-50 focus:bg-white transition-colors outline-none text-sm"
                                    placeholder="John Doe"
                                    onChange={handleChange}
                                />
                            </div>
                        </div>

                        <div>
                            <label className="block text-xs font-semibold text-gray-600 uppercase tracking-wide mb-1">Email Address</label>
                            <div className="relative">
                                <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                    <Mail size={16} className="text-gray-400" />
                                </div>
                                <input
                                    type="email"
                                    name="email"
                                    required
                                    className="block w-full pl-10 pr-3 py-2.5 border border-gray-200 rounded-xl focus:ring-indigo-500 focus:border-indigo-500 bg-gray-50 focus:bg-white transition-colors outline-none text-sm"
                                    placeholder="student@university.edu"
                                    onChange={handleChange}
                                />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-semibold text-gray-600 uppercase tracking-wide mb-1">Password</label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <Lock size={16} className="text-gray-400" />
                                    </div>
                                    <input
                                        type="password"
                                        name="password"
                                        required
                                        className="block w-full pl-10 pr-3 py-2.5 border border-gray-200 rounded-xl focus:ring-indigo-500 focus:border-indigo-500 bg-gray-50 focus:bg-white transition-colors outline-none text-sm"
                                        placeholder="••••••••"
                                        onChange={handleChange}
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="block text-xs font-semibold text-gray-600 uppercase tracking-wide mb-1">Confirm</label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <Lock size={16} className="text-gray-400" />
                                    </div>
                                    <input
                                        type="password"
                                        name="confirmPassword"
                                        required
                                        className="block w-full pl-10 pr-3 py-2.5 border border-gray-200 rounded-xl focus:ring-indigo-500 focus:border-indigo-500 bg-gray-50 focus:bg-white transition-colors outline-none text-sm"
                                        placeholder="••••••••"
                                        onChange={handleChange}
                                    />
                                </div>
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                            <div>
                                <label className="block text-xs font-semibold text-gray-600 uppercase tracking-wide mb-1">Department</label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <BookOpen size={16} className="text-gray-400" />
                                    </div>
                                    <input
                                        type="text"
                                        name="department"
                                        required
                                        className="block w-full pl-10 pr-3 py-2.5 border border-gray-200 rounded-xl focus:ring-indigo-500 focus:border-indigo-500 bg-gray-50 focus:bg-white transition-colors outline-none text-sm"
                                        placeholder="E.g. CS"
                                        onChange={handleChange}
                                    />
                                </div>
                            </div>
                            <div>
                                <label className="block text-xs font-semibold text-gray-600 uppercase tracking-wide mb-1">Year</label>
                                <div className="relative">
                                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                        <Calendar size={16} className="text-gray-400" />
                                    </div>
                                    <select
                                        name="year"
                                        required
                                        className="block w-full pl-10 pr-8 py-2.5 border border-gray-200 rounded-xl focus:ring-indigo-500 focus:border-indigo-500 bg-gray-50 focus:bg-white transition-colors outline-none text-sm appearance-none"
                                        onChange={handleChange}
                                        defaultValue=""
                                    >
                                        <option value="" disabled>Select</option>
                                        <option value="1">1st Year</option>
                                        <option value="2">2nd Year</option>
                                        <option value="3">3rd Year</option>
                                        <option value="4">4th Year</option>
                                    </select>
                                </div>
                            </div>
                        </div>

                        <button
                            type="submit"
                            disabled={loading}
                            className="w-full flex items-center justify-center gap-2 bg-indigo-600 hover:bg-indigo-700 text-white font-semibold py-3 px-4 rounded-xl transition-all shadow-md mt-6 disabled:opacity-70"
                        >
                            {loading ? (
                                <Loader className="animate-spin" size={20} />
                            ) : (
                                <>
                                    Create Account <ArrowRight size={18} />
                                </>
                            )}
                        </button>
                    </form>

                    <div className="mt-8 text-center text-sm text-gray-600">
                        Already have an account?{' '}
                        <Link to="/login" className="text-indigo-600 font-semibold hover:underline">
                            Sign In
                        </Link>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default Register;

import { useState, useEffect, useContext } from 'react';
import { Link } from 'react-router-dom';
import api from '../api/axios';
import AuthContext from '../context/AuthContext';
import { Building, ClipboardList, Info, AlertCircle, Repeat } from 'lucide-react';

const StudentDashboard = () => {
    const { user } = useContext(AuthContext);
    const [application, setApplication] = useState(null);
    const [rooms, setRooms] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    useEffect(() => {
        fetchDashboardData();
    }, []);

    const fetchDashboardData = async () => {
        try {
            try {
                const { data: appData } = await api.get('/student/status');
                setApplication(appData);
            } catch (err) {
                if (err.response?.status !== 404) {
                    throw err;
                }
            }

            const { data: roomData } = await api.get('/student/rooms');
            setRooms(roomData);
        } catch (err) {
            setError('Failed to fetch dashboard data');
        } finally {
            setLoading(false);
        }
    };

    if (loading) {
        return (
            <div className="flex justify-center items-center h-[calc(100vh-64px)] bg-gray-50">
                <div className="animate-spin rounded-full h-12 w-12 border-t-4 border-blue-600"></div>
            </div>
        );
    }

    const availableRoomsCount = rooms.length;

    return (
        <div className="min-h-[calc(100vh-64px)] bg-gray-50 p-6 md:p-12">
            <div className="max-w-6xl mx-auto space-y-8">

                {/* Header */}
                <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100 mb-8">
                    <h1 className="text-3xl font-bold text-gray-900">Welcome, {user?.name} 👋</h1>
                    <p className="text-gray-500 mt-2">Manage your hostel room application from this control panel.</p>
                </div>

                {error && (
                    <div className="bg-red-50 text-red-600 p-4 rounded-xl flex items-center gap-2 font-medium mb-8">
                        <AlertCircle size={20} />
                        {error}
                    </div>
                )}

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
                    {/* Status Summary Card */}
                    <div className="bg-indigo-600 rounded-3xl p-8 text-white shadow-lg shadow-indigo-200 flex flex-col justify-center">
                        <h2 className="text-indigo-100 font-semibold uppercase tracking-wider text-sm mb-2">Application Status</h2>
                        {application ? (
                            <>
                                <h3 className="text-4xl font-black mb-4">{application.status}</h3>
                                <p className="text-indigo-100">For Block {application.roomId?.block}</p>
                            </>
                        ) : (
                            <>
                                <h3 className="text-4xl font-black mb-4">Not Applied</h3>
                                <p className="text-indigo-100">You haven't submitted an application yet.</p>
                            </>
                        )}
                    </div>

                    {/* Rooms Summary Card */}
                    <div className="bg-white border border-gray-100 rounded-3xl p-8 shadow-sm flex items-center gap-6">
                        <div className="bg-blue-50 text-blue-600 p-6 rounded-2xl">
                            <Building size={48} />
                        </div>
                        <div>
                            <h2 className="text-gray-500 font-semibold uppercase tracking-wider text-sm mb-1">Available Blocks</h2>
                            <h3 className="text-5xl font-black text-gray-900">{availableRoomsCount}</h3>
                        </div>
                    </div>
                </div>

                <h2 className="text-xl font-bold text-gray-900 mb-4 mt-8">Quick Navigation</h2>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                    <Link
                        to="/student/apply"
                        className="group bg-white border border-gray-100 p-6 rounded-3xl shadow-sm hover:shadow-md transition-all flex flex-col items-center text-center gap-4 hover:-translate-y-1"
                    >
                        <div className="bg-green-50 text-green-600 p-4 rounded-full group-hover:scale-110 transition-transform">
                            <ClipboardList size={32} />
                        </div>
                        <span className="font-bold text-gray-900">Apply for a Room</span>
                    </Link>

                    <Link
                        to="/student/status"
                        className="group bg-white border border-gray-100 p-6 rounded-3xl shadow-sm hover:shadow-md transition-all flex flex-col items-center text-center gap-4 hover:-translate-y-1"
                    >
                        <div className="bg-orange-50 text-orange-600 p-4 rounded-full group-hover:scale-110 transition-transform">
                            <Info size={32} />
                        </div>
                        <span className="font-bold text-gray-900">View Status</span>
                    </Link>

                    <Link
                        to="/student/rooms"
                        className="group bg-white border border-gray-100 p-6 rounded-3xl shadow-sm hover:shadow-md transition-all flex flex-col items-center text-center gap-4 hover:-translate-y-1"
                    >
                        <div className="bg-blue-50 text-blue-600 p-4 rounded-full group-hover:scale-110 transition-transform">
                            <Building size={32} />
                        </div>
                        <span className="font-bold text-gray-900">View Rooms</span>
                    </Link>

                    <Link
                        to="/student/transfer"
                        className="group bg-white border border-gray-100 p-6 rounded-3xl shadow-sm hover:shadow-md transition-all flex flex-col items-center text-center gap-4 hover:-translate-y-1"
                    >
                        <div className="bg-purple-50 text-purple-600 p-4 rounded-full group-hover:scale-110 transition-transform">
                            <Repeat size={32} />
                        </div>
                        <span className="font-bold text-gray-900">Request Transfer</span>
                    </Link>
                </div>

            </div>
        </div>
    );
};

export default StudentDashboard;

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api/axios';
import { Repeat, Building, AlertCircle, CheckCircle } from 'lucide-react';

const TransferRequest = () => {
    const [currentRoom, setCurrentRoom] = useState(null);
    const [rooms, setRooms] = useState([]);
    const [requestedRoomId, setRequestedRoomId] = useState('');
    const [reason, setReason] = useState('');

    // UI state
    const [loading, setLoading] = useState(true);
    const [submitting, setSubmitting] = useState(false);
    const [error, setError] = useState('');
    const [success, setSuccess] = useState('');

    const navigate = useNavigate();

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            // Check application status for current room
            try {
                const { data: statusData } = await api.get('/student/status');
                if (statusData && statusData.status === 'Approved') {
                    setCurrentRoom(statusData.roomId);
                }
            } catch (err) {
                if (err.response?.status !== 404) throw err;
            }

            // Fetch available rooms
            const { data: roomData } = await api.get('/student/rooms');
            setRooms(roomData);
        } catch (err) {
            setError('Failed to load required data. Please try again later.');
        } finally {
            setLoading(false);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setError('');
        setSuccess('');

        if (!requestedRoomId) {
            setError('Please select a requested room block.');
            return;
        }

        setSubmitting(true);

        try {
            await api.post('/student/transfer', {
                requestedRoomId,
                reason
            });
            setSuccess('Transfer request submitted successfully. Waiting for admin approval.');
            setRequestedRoomId('');
            setReason('');
        } catch (err) {
            setError(err.response?.data?.message || 'Failed to submit transfer request.');
        } finally {
            setSubmitting(false);
        }
    };

    if (loading) {
        return (
            <div className="flex justify-center items-center h-full p-12">
                <div className="animate-spin rounded-full h-12 w-12 border-t-4 border-blue-600"></div>
            </div>
        );
    }

    return (
        <div className="p-6 md:p-12">
            <div className="max-w-3xl mx-auto space-y-8">

                <div className="bg-white p-8 rounded-3xl shadow-sm border border-gray-100 mb-8">
                    <h1 className="text-3xl font-bold text-gray-900 flex items-center gap-3">
                        <Repeat size={36} className="text-purple-600" />
                        Room Transfer Request
                    </h1>
                    <p className="text-gray-500 mt-2">Request to change your currently allocated room to a different block.</p>
                </div>

                {!currentRoom ? (
                    <div className="bg-white p-12 rounded-3xl border border-gray-100 text-center shadow-sm">
                        <Building className="mx-auto text-gray-300 mb-4" size={48} />
                        <h3 className="text-xl font-bold text-gray-900 mb-2">Transfer Not Available</h3>
                        <p className="text-gray-500 mb-6">You must have an approved room allocation before requesting a transfer.</p>
                        <button onClick={() => navigate('/student/apply')} className="bg-blue-600 hover:bg-blue-700 text-white px-6 py-2 rounded-xl transition-colors font-semibold">
                            Apply for a Room First
                        </button>
                    </div>
                ) : (
                    <div className="bg-white border border-gray-100 rounded-3xl shadow-sm overflow-hidden">
                        <div className="p-8">
                            {error && (
                                <div className="bg-red-50 text-red-600 p-4 rounded-xl flex items-center gap-2 font-medium mb-6">
                                    <AlertCircle size={20} />
                                    {error}
                                </div>
                            )}

                            {success && (
                                <div className="bg-green-50 text-green-700 p-4 rounded-xl flex items-center gap-2 font-medium mb-6">
                                    <CheckCircle size={20} />
                                    {success}
                                </div>
                            )}

                            <div className="bg-gray-50 p-6 rounded-2xl border border-gray-100 mb-8 flex items-center justify-between">
                                <div>
                                    <span className="text-xs uppercase tracking-wider font-bold text-gray-500">Current Room Block</span>
                                    <h3 className="text-2xl font-black text-gray-900 mt-1">{currentRoom.block}</h3>
                                </div>
                                <Building size={40} className="text-gray-300" />
                            </div>

                            <form onSubmit={handleSubmit} className="space-y-6">
                                <div>
                                    <label className="block text-sm font-semibold text-gray-700 mb-2">Select Requested Block</label>
                                    <select
                                        value={requestedRoomId}
                                        onChange={(e) => setRequestedRoomId(e.target.value)}
                                        className="w-full border border-gray-200 bg-gray-50 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:bg-white transition-colors"
                                        required
                                    >
                                        <option value="">-- Choose a block --</option>
                                        {rooms.map(room => (
                                            <option key={room._id} value={room._id} disabled={room._id === currentRoom._id}>
                                                {room.block} {room._id === currentRoom._id ? '(Current)' : ''} - (Total: {room.totalRooms}, Available: {room.totalRooms - room.occupiedRooms})
                                            </option>
                                        ))}
                                    </select>
                                </div>

                                <div>
                                    <label className="block text-sm font-semibold text-gray-700 mb-2">Reason for Transfer (Optional)</label>
                                    <textarea
                                        value={reason}
                                        onChange={(e) => setReason(e.target.value)}
                                        className="w-full border border-gray-200 bg-gray-50 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-purple-500 focus:bg-white transition-colors"
                                        rows="4"
                                        placeholder="Briefly explain why you want to transfer..."
                                    ></textarea>
                                </div>

                                <button
                                    type="submit"
                                    disabled={submitting}
                                    className={`w-full text-white font-bold py-4 rounded-xl transition-all flex justify-center items-center shadow-md ${submitting ? 'bg-purple-400 cursor-not-allowed' : 'bg-purple-600 hover:bg-purple-700 hover:shadow-lg'
                                        }`}
                                >
                                    {submitting ? 'Submitting Request...' : 'Submit Transfer Request'}
                                </button>
                            </form>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

