import { useState, useEffect, useContext } from 'react';
import api from '../../api/axios';
import AuthContext from '../../context/AuthContext';
import { Users, Building, Settings, CheckCircle, XCircle, Trash2, PlusCircle, BarChart3, Edit2, Activity } from 'lucide-react';
import Sidebar from '../../components/Sidebar';
import Reports from './Reports';

const AdminDashboard = () => {
    const { user } = useContext(AuthContext);
    const [activeTab, setActiveTab] = useState('applications'); // applications, rooms, reports
    const [applications, setApplications] = useState([]);
    const [roomStats, setRoomStats] = useState(null);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

    // Add/Edit Room State
    const [newRoomBlock, setNewRoomBlock] = useState('');
    const [newRoomTotal, setNewRoomTotal] = useState('');
    const [editingRoomId, setEditingRoomId] = useState(null);

    useEffect(() => {
        if (activeTab === 'applications') fetchApplications();
        if (activeTab === 'rooms') fetchRoomStats();
    }, [activeTab]);

    const fetchApplications = async () => {
        setLoading(true);
        try {
            const { data } = await api.get('/admin/applications');
            setApplications(data);
        } catch (err) {
            setError('Failed to fetch applications');
        } finally {
            setLoading(false);
        }
    };

    const fetchRoomStats = async () => {
        setLoading(true);
        try {
            const { data } = await api.get('/rooms/stats');
            setRoomStats(data);
        } catch (err) {
            setError('Failed to fetch room statistics');
        } finally {
            setLoading(false);
        }
    };

    const handleApprove = async (id) => {
        try {
            await api.put(`/admin/approve/${id}`);
            fetchApplications();
        } catch (err) {
            setError(err.response?.data?.message || 'Approval failed');
        }
    };

    const handleReject = async (id) => {
        try {
            await api.put(`/admin/reject/${id}`);
            fetchApplications();
        } catch (err) {
            setError(err.response?.data?.message || 'Rejection failed');
        }
    };

    const handleDeleteApp = async (id) => {
        if (window.confirm('Delete this application record permanently?')) {
            try {
                await api.delete(`/admin/application/${id}`);
                fetchApplications();
            } catch (err) {
                setError('Failed to delete');
            }
        }
    };

    const handleRoomSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editingRoomId) {
                await api.put(`/rooms/${editingRoomId}`, { block: newRoomBlock, totalRooms: Number(newRoomTotal) });
                setEditingRoomId(null);
            } else {
                await api.post('/rooms/add', { block: newRoomBlock, totalRooms: Number(newRoomTotal) });
            }
            setNewRoomBlock('');
            setNewRoomTotal('');
            fetchRoomStats();
        } catch (err) {
            setError(err.response?.data?.message || `Failed to ${editingRoomId ? 'update' : 'add'} room`);
        }
    };

    const handleEditClick = (room) => {
        setEditingRoomId(room._id);
        setNewRoomBlock(room.block);
        setNewRoomTotal(room.totalRooms.toString());
    };

    const handleCancelEdit = () => {
        setEditingRoomId(null);
        setNewRoomBlock('');
        setNewRoomTotal('');
    };

    const handleDeleteRoom = async (id) => {
        if (window.confirm('Delete this room block completely?')) {
            try {
                await api.delete(`/rooms/delete/${id}`);
                fetchRoomStats();
            } catch (err) {
                setError(err.response?.data?.message || 'Failed to delete room');
            }
        }
    };

    return (
    const titleRender = () => (
            <h2 className="text-xl font-black text-gray-900 tracking-tight">Admin<span className="text-red-500">Panel</span></h2>
        );

    const adminLinks = [
        { id: 'applications', icon: Users, label: 'Applications' },
        { id: 'rooms', icon: Building, label: 'Manage Rooms' },
        { id: 'reports', icon: Activity, label: 'Reports' },
    ];

    return (
        <div className="min-h-[calc(100vh-64px)] bg-gray-50 flex flex-col md:flex-row">
            {/* Sidebar Navigation */}
            <Sidebar
                titleRender={titleRender}
                subtitle={user?.email}
                items={adminLinks}
                activeItem={activeTab}
                onSelectItem={setActiveTab}
            />

            {/* Main Content Area */}
            <div className="flex-1 p-6 md:p-10 overflow-y-auto w-full">
                {error && (
                    <div className="bg-red-50 text-red-600 p-4 rounded-xl mb-6 font-medium text-sm flex justify-between items-center border border-red-100">
                        {error}
                        <button onClick={() => setError('')} className="text-red-400 hover:text-red-600"><XCircle size={18} /></button>
                    </div>
                )}

                {/* Applications Tab */}
                {activeTab === 'applications' && (
                    <div className="space-y-6">
                        <div className="flex justify-between items-center bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
                            <h1 className="text-2xl font-bold text-gray-900">Student Applications</h1>
                            <span className="bg-gray-100 text-gray-700 px-4 py-1.5 rounded-full text-sm font-bold">
                                Total: {applications.length}
                            </span>
                        </div>

                        {loading ? (
                            <div className="flex justify-center p-12"><div className="animate-spin rounded-full h-8 w-8 border-t-2 border-red-500"></div></div>
                        ) : applications.length === 0 ? (
                            <div className="bg-white p-12 rounded-3xl border border-gray-100 text-center shadow-sm">
                                <Users className="mx-auto text-gray-300 mb-4" size={48} />
                                <h3 className="text-lg font-semibold text-gray-700">No Applications</h3>
                                <p className="text-gray-500">There are currently no student applications to review.</p>
                            </div>
                        ) : (
                            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                                {applications.map((app) => (
                                    <div key={app._id} className="bg-white border border-gray-100 rounded-3xl p-6 shadow-sm hover:shadow-md transition-shadow relative overflow-hidden group">
                                        <div className={`absolute top-0 right-0 w-2 h-full ${app.status === 'Approved' ? 'bg-green-500' :
                                            app.status === 'Rejected' ? 'bg-red-500' : 'bg-yellow-400'
                                            }`}></div>

                                        <div className="flex justify-between items-start mb-4 pr-4">
                                            <div>
                                                <h3 className="text-xl font-bold text-gray-900">{app.studentId?.name}</h3>
                                                <p className="text-sm text-gray-500">{app.studentId?.email}</p>
                                            </div>
                                            <span className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wider ${app.status === 'Approved' ? 'bg-green-100 text-green-700' :
                                                app.status === 'Rejected' ? 'bg-red-100 text-red-700' : 'bg-yellow-100 text-yellow-700'
                                                }`}>
                                                {app.status}
                                            </span>
                                        </div>

                                        <div className="bg-gray-50 rounded-xl p-4 mb-6 space-y-2">
                                            <div className="flex justify-between text-sm">
                                                <span className="text-gray-500">Department</span>
                                                <span className="font-semibold text-gray-800">{app.studentId?.department}</span>
                                            </div>
                                            <div className="flex justify-between text-sm">
                                                <span className="text-gray-500">Year</span>
                                                <span className="font-semibold text-gray-800">{app.studentId?.year}</span>
                                            </div>
                                            <div className="flex justify-between text-sm pt-2 border-t border-gray-200 mt-2">
                                                <span className="text-gray-500">Requested Block</span>
                                                <span className="font-bold text-blue-600">{app.roomId?.block}</span>
                                            </div>
                                            <div className="text-xs text-gray-400 mt-2">
                                                Applied: {new Date(app.appliedDate).toLocaleDateString()}
                                            </div>
                                        </div>

                                        <div className="flex gap-2">
                                            {app.status === 'Pending' && (
                                                <>
                                                    <button
                                                        onClick={() => handleApprove(app._id)}
                                                        className="flex-1 bg-green-500 hover:bg-green-600 text-white py-2 rounded-xl text-sm font-semibold transition-colors flex items-center justify-center gap-1"
                                                    >
                                                        <CheckCircle size={16} /> Approve
                                                    </button>
                                                    <button
                                                        onClick={() => handleReject(app._id)}
                                                        className="flex-1 bg-gray-200 hover:bg-red-500 hover:text-white text-gray-700 py-2 rounded-xl text-sm font-semibold transition-colors flex items-center justify-center gap-1"
                                                    >
                                                        <XCircle size={16} /> Reject
                                                    </button>
                                                </>
                                            )}

                                            <button
                                                onClick={() => handleDeleteApp(app._id)}
                                                className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-colors ml-auto"
                                                title="Delete Record"
                                            >
                                                <Trash2 size={20} />
                                            </button>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        )}
                    </div>
                )}

                {/* Manage Rooms Tab */}
                {activeTab === 'rooms' && roomStats && (
                    <div className="space-y-8">
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                            <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm flex items-center gap-4">
                                <div className="bg-blue-100 p-4 rounded-2xl text-blue-600"><Building size={32} /></div>
                                <div>
                                    <p className="text-gray-500 text-sm font-medium uppercase tracking-wider">Total Rooms</p>
                                    <h3 className="text-3xl font-black text-gray-900">{roomStats.totalRooms}</h3>
                                </div>
                            </div>
                            <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm flex items-center gap-4">
                                <div className="bg-green-100 p-4 rounded-2xl text-green-600"><CheckCircle size={32} /></div>
                                <div>
                                    <p className="text-gray-500 text-sm font-medium uppercase tracking-wider">Occupied</p>
                                    <h3 className="text-3xl font-black text-gray-900">{roomStats.occupiedRooms}</h3>
                                </div>
                            </div>
                            <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm flex items-center gap-4">
                                <div className="bg-orange-100 p-4 rounded-2xl text-orange-600"><BarChart3 size={32} /></div>
                                <div>
                                    <p className="text-gray-500 text-sm font-medium uppercase tracking-wider">Available</p>
                                    <h3 className="text-3xl font-black text-gray-900">{roomStats.availableRooms}</h3>
                                </div>
                            </div>
                        </div>

                        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">

                            {/* Add/Edit Room Form */}
                            <div className="lg:col-span-1">
                                <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm sticky top-6">
                                    <h3 className="text-lg font-bold text-gray-900 mb-6 flex items-center gap-2">
                                        {editingRoomId ? <Edit2 size={20} className="text-blue-500" /> : <PlusCircle size={20} className="text-red-500" />}
                                        {editingRoomId ? 'Edit Room Block' : 'Add New Block'}
                                    </h3>
                                    <form onSubmit={handleRoomSubmit} className="space-y-4">
                                        <div>
                                            <label className="block text-sm font-semibold text-gray-700 mb-1">Block Name (e.g., A1)</label>
                                            <input
                                                type="text"
                                                required
                                                value={newRoomBlock}
                                                onChange={e => setNewRoomBlock(e.target.value)}
                                                className="w-full border border-gray-200 rounded-xl px-4 py-2.5 focus:border-red-500 focus:ring-1 focus:ring-red-500 text-sm outline-none"
                                                placeholder="Block Name"
                                            />
                                        </div>
                                        <div>
                                            <label className="block text-sm font-semibold text-gray-700 mb-1">Total Capacity</label>
                                            <input
                                                type="number"
                                                required
                                                min="1"
                                                value={newRoomTotal}
                                                onChange={e => setNewRoomTotal(e.target.value)}
                                                className="w-full border border-gray-200 rounded-xl px-4 py-2.5 focus:border-red-500 focus:ring-1 focus:ring-red-500 text-sm outline-none"
                                                placeholder="Number of rooms"
                                            />
                                        </div>
                                        <div className="flex gap-2">
                                            <button type="submit" className={`flex-1 font-bold py-3 rounded-xl transition-colors shadow-sm mt-4 text-white ${editingRoomId ? 'bg-blue-600 hover:bg-blue-700' : 'bg-red-600 hover:bg-red-700'}`}>
                                                {editingRoomId ? 'Update Block' : 'Create Block'}
                                            </button>
                                            {editingRoomId && (
                                                <button type="button" onClick={handleCancelEdit} className="flex-1 bg-gray-200 hover:bg-gray-300 text-gray-800 font-bold py-3 rounded-xl transition-colors shadow-sm mt-4">
                                                    Cancel
                                                </button>
                                            )}
                                        </div>
                                    </form>
                                </div>
                            </div>

                            {/* Room List */}
                            <div className="lg:col-span-2">
                                <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
                                    <div className="p-6 border-b border-gray-100 flex justify-between items-center">
                                        <h3 className="text-lg font-bold text-gray-900">Existing Room Blocks</h3>
                                    </div>

                                    <div className="overflow-x-auto">
                                        <table className="w-full text-left border-collapse">
                                            <thead>
                                                <tr className="bg-gray-50 border-b border-gray-100 text-xs uppercase tracking-wider text-gray-500">
                                                    <th className="p-4 font-semibold">Block Name</th>
                                                    <th className="p-4 font-semibold">Capacity</th>
                                                    <th className="p-4 font-semibold">Occupied</th>
                                                    <th className="p-4 font-semibold">Status</th>
                                                    <th className="p-4 font-semibold text-right">Actions</th>
                                                </tr>
                                            </thead>
                                            <tbody className="divide-y divide-gray-100">
                                                {roomStats.roomsList.map(room => (
                                                    <tr key={room._id} className="hover:bg-gray-50 transition-colors">
                                                        <td className="p-4 font-bold text-gray-900">{room.block}</td>
                                                        <td className="p-4 text-gray-600 font-medium">{room.totalRooms}</td>
                                                        <td className="p-4 text-gray-600 font-medium">{room.occupiedRooms}</td>
                                                        <td className="p-4">
                                                            <div className="w-24 h-2 bg-gray-200 rounded-full overflow-hidden flex">
                                                                <div
                                                                    className={`h-full ${room.occupiedRooms >= room.totalRooms ? 'bg-red-500' : 'bg-green-500'}`}
                                                                    style={{ width: `${(room.occupiedRooms / room.totalRooms) * 100}%` }}
                                                                ></div>
                                                            </div>
                                                        </td>
                                                        <td className="p-4 text-right flex justify-end gap-2">
                                                            <button
                                                                onClick={() => handleEditClick(room)}
                                                                className="text-gray-400 hover:text-blue-500 bg-white hover:bg-blue-50 p-2 rounded-lg transition-colors border border-gray-200 hover:border-blue-100"
                                                                title="Edit Block"
                                                            >
                                                                <Edit2 size={16} />
                                                            </button>
                                                            <button
                                                                onClick={() => handleDeleteRoom(room._id)}
                                                                className="text-gray-400 hover:text-red-500 bg-white hover:bg-red-50 p-2 rounded-lg transition-colors border border-gray-200 hover:border-red-100"
                                                                title="Delete Block"
                                                            >
                                                                <Trash2 size={16} />
                                                            </button>
                                                        </td>
                                                    </tr>
                                                ))}
                                                {roomStats.roomsList.length === 0 && (
                                                    <tr>
                                                        <td colSpan="5" className="p-8 text-center text-gray-500">
                                                            No room blocks defined yet.
                                                        </td>
                                                    </tr>
                                                )}
                                            </tbody>
                                        </table>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Reports Tab */}
                {activeTab === 'reports' && <Reports />}

            </div>
        </div>
    );
};

export default AdminDashboard;

