import { PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Legend } from 'recharts';
import { Activity, Users, Building } from 'lucide-react';

const COLORS = ['#10B981', '#3B82F6', '#EF4444']; // Green, Blue, Red
const ROOM_COLORS = ['#3B82F6', '#10B981']; // Blue for Occupied, Green for Available

const Reports = () => {
    const [stats, setStats] = useState({ rooms: null, applications: null });
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState('');

